// Search PyraStore products - uses $http (n8n compatible)
const baseUrl = "https://events.pyramedia.info/api";

const categoryMap = {
  "الكترونيات": "electronics", "إلكترونيات": "electronics", "الكترونيا": "electronics", "الكتروني": "electronics",
  "جمال": "beauty", "تجميل": "beauty", "بيوتي": "beauty", "كريم": "beauty", "عناية": "beauty",
  "ازياء": "fashion", "أزياء": "fashion", "ملابس": "fashion", "شنط": "fashion", "شنطة": "fashion", "ساعة": "fashion", "ساعات": "fashion",
  "العاب": "toys", "ألعاب": "toys", "لعب": "toys", "لعبة": "toys",
  "منزل": "home", "بيت": "home", "منزلي": "home", "مطبخ": "home",
  "electronics": "electronics", "beauty": "beauty", "fashion": "fashion",
  "toys": "toys", "home": "home"
};

let input;
try { input = JSON.parse(query); } catch(e) { input = { q: query }; }
const searchQuery = (input.q || input.query || input.search || query).trim().toLowerCase();

try {
  const resp = await this.helpers.httpRequest({
    method: "GET",
    url: baseUrl + "/products.php",
    returnFullResponse: false
  });

  let products = resp.products || [];

  const matchedCategory = categoryMap[searchQuery];

  let filtered;
  if (matchedCategory) {
    filtered = products.filter(p => p.category === matchedCategory);
  } else {
    filtered = products.filter(p => 
      p.title && p.title.toLowerCase().includes(searchQuery)
    );
    if (filtered.length === 0) {
      const words = searchQuery.split(/\s+/);
      filtered = products.filter(p => 
        words.some(w => w.length > 2 && p.title && p.title.toLowerCase().includes(w.toLowerCase()))
      );
    }
  }

  if (filtered.length === 0) {
    filtered = products.slice(0, 5);
    let result = "لم أجد نتائج مطابقة. إليك أحدث المنتجات:\n\n";
    for (const p of filtered) {
      result += "🆔 " + p.id + " | 📦 " + p.title.substring(0, 60) + "\n";
      result += "💰 " + p.price + " AED | 🏷️ " + (p.category || "عام") + "\n";
      result += "🔗 " + (p.affiliate_link || "") + "\n";
      result += "🖼️ " + (p.image_url || "") + "\n---\n";
    }
    result += "\nالفئات المتاحة: إلكترونيات، جمال، أزياء، ألعاب، منزل";
    return result;
  }

  filtered = filtered.slice(0, 5);
  let result = "نتائج البحث (" + filtered.length + " منتجات):\n\n";
  for (const p of filtered) {
    result += "🆔 " + p.id + " | 📦 " + p.title.substring(0, 60) + "\n";
    result += "💰 " + p.price + " AED | 🏷️ " + (p.category || "عام") + "\n";
    result += "🔗 " + (p.affiliate_link || "") + "\n";
    result += "🖼️ " + (p.image_url || "") + "\n---\n";
  }
  return result;
} catch(e) {
  return "خطأ في البحث: " + e.message;
}

// Send product image via Telegram using $http
const botToken = "***REMOVED***";
let input;
try { input = JSON.parse(query); } catch(e) { return "Error: Input must be JSON with image_url and chat_id"; }

const imageUrl = input.image_url || input.url;
const chatId = input.chat_id;
const caption = input.caption || "";

if (!imageUrl || !chatId) return "Error: Missing image_url or chat_id";

try {
  const resp = await this.helpers.httpRequest({
    method: "POST",
    url: "https://api.telegram.org/bot" + botToken + "/sendPhoto",
    body: {
      chat_id: chatId,
      photo: imageUrl,
      caption: caption,
      parse_mode: "Markdown"
    },
    headers: { "Content-Type": "application/json" }
  });
  return "Image sent successfully!";
} catch(e) {
  return "Error sending image: " + e.message;
}

// Save order to Supabase using $http
const supabaseUrl = "https://db.pyramedia.info";
const supabaseKey = "***REMOVED***";

let input;
try { input = JSON.parse(query); } catch(e) { return "Error: Input must be valid JSON"; }

try {
  const resp = await this.helpers.httpRequest({
    method: "POST",
    url: supabaseUrl + "/rest/v1/pyrastore_orders",
    headers: {
      "apikey": supabaseKey,
      "Authorization": "Bearer " + supabaseKey,
      "Content-Type": "application/json",
      "Prefer": "return=representation"
    },
    body: {
      telegram_chat_id: String(input.chat_id || ""),
      telegram_username: input.username || "",
      customer_name: input.name || "",
      customer_phone: input.phone || "",
      customer_address: input.address || "",
      payment_method: input.payment || "",
      products: input.products || [],
      total_amount: input.total || 0,
      status: "pending",
      notes: input.notes || ""
    }
  });
  return "تم حفظ الأوردر بنجاح! رقم الأوردر: " + (resp[0]?.id || "saved");
} catch(e) {
  return "Error saving order: " + e.message;
}

